import React, { useState } from 'react';
import { Container, Row, Col } from 'react-bootstrap';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './components/Login';
import NavigationBar from './components/Navbar';
import Cart from './components/Cart';
import PartsSearch from './pages/PartsSearch';
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';

function AppContent() {
  const { isAuthenticated } = useAuth();
  const [cartItems, setCartItems] = useState([]);

  const addToCart = (part) => {
    setCartItems(prevItems => {
      const existingItem = prevItems.find(item => item.id === part.id);
      if (existingItem) {
        return prevItems.map(item =>
          item.id === part.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prevItems, { ...part, quantity: 1 }];
    });
  };

  const removeFromCart = (partId) => {
    setCartItems(prevItems => prevItems.filter(item => item.id !== partId));
  };

  const clearCart = () => setCartItems([]);

  if (!isAuthenticated) {
    return <Login />;
  }

  return (
    <div className="App">
      <NavigationBar cartCount={cartItems.length} />

      <Container fluid className="main-content">
        <Row>
          <Col md={9}>
            <PartsSearch onAddToCart={addToCart} />
          </Col>

          <Col md={3}>
            <Cart 
              items={cartItems}
              onRemoveItem={removeFromCart}
              onClearCart={clearCart}
            />
          </Col>
        </Row>
      </Container>
    </div>
  );
}

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;
